mapper.select:
select o.*,
       coalesce(nullif(o.member_name, ''), m.name) as member_name,
       coalesce(nullif(o.member_phone, ''), m.phone) as member_phone,
       d.dept_name
from member_card_order o
left join member m on o.member_id = m.id
left join sys_dept d on o.dept_id = d.dept_id

    o.is_del = 0
    and o.order_no like concat('%', #{orderNo}, '%')
    and o.member_card_id = #{memberCardId}
    and o.member_id = #{memberId}
    and o.member_no like concat('%', #{memberNo}, '%')
    and coalesce(nullif(o.member_name, ''), m.name) like concat('%', #{memberNameLike}, '%')
    and coalesce(nullif(o.member_phone, ''), m.phone) like concat('%', #{memberPhone}, '%')
    and o.card_type_id = #{cardTypeId}
    and o.card_type_name like concat('%', #{cardTypeName}, '%')
    and o.payment_type = #{paymentType}
    and o.order_status = #{orderStatus}
    and o.dept_id = #{deptId}
    and o.create_staff_name like concat('%', #{createStaffName}, '%')
    and o.pay_time >= #{beginPayTime}
    and o.pay_time <= #{endPayTime}
    and o.created_at >= #{beginCreatedAt}
    and o.created_at <= #{endCreatedAt}
    ${params.dataScope}

order by o.pay_time desc, o.created_at desc, o.id desc
